const body = $input.first().json.body || $input.first().json;
const ahora = new Date();
const lead = {
  id: 'WEB-' + ahora.getTime(),
  nombre: body.nombre || body.full_name || body.name || 'Sin nombre',
  telefono: body.telefono || body.phone || '',
  email: body.email || body.correo || '',
  evento: body.tipo_evento || body.tipoEvento || 'No especificado',
  fecha_evento: body.fecha_evento || body.fecha || body.event_date || 'No especificada',
  personas: body.num_personas || body.personas || body.guests || 'No especificado',
  paquete: body.paquete_interes || body.paquete || '',
  mensaje: body.mensaje || '',
  fuente: body.fuente || 'Sitio Web',
  status: 'nuevo',
  fecha_captura: ahora.toLocaleString('es-MX', { timeZone: 'America/Mexico_City' }),
  ultimo_email: ''
};
return [{ json: lead }];
